/**
 * Cross-implementation conformance: the TypeScript reference must keep
 * producing the committed corpus, and the Rust crate asserts against the same
 * files (`crates/wh40kdc/tests/conformance.rs`). The corpus is generated by
 * `npm run gen:conformance`; a CI drift guard keeps it current.
 *
 * Three layers are pinned:
 * 1. `normalizeName` against every entry in `normalize.json`.
 * 2. Every roster fixture: each `input.*` file imports to the same
 *    `expected.roster.json`.
 * 3. Every export target: `exportRoster(roster, fmt)` reproduces each
 *    `expected.<fmt>.{txt,json}` golden byte-for-byte.
 */
import { describe, it, expect } from "vitest";
import { readdirSync, readFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

import { Dataset } from "../src/data/dataset.js";
import { normalizeName } from "../src/data/normalize.js";
import { maximalLoadout } from "../src/data/loadout.js";
import { exportRoster, type ExportFormat } from "../src/export/index.js";
import { importRoster, tryImportRoster, REGISTERED_ADAPTERS } from "../src/import/import-roster.js";
import { selectAdapter } from "../src/import/adapter.js";
import type { RosterFormat } from "../src/import/types.js";
import { crunch, type Buff, type EngineContext, type Stage } from "../src/cruncher/index.js";
import { attributeStages } from "../src/cruncher/attribution.js";
import type { Phase } from "../src/generated.js";
import { effectToBuffs } from "../src/cruncher/from-dsl.js";
import { encodeBase } from "../src/runner.js";
import type { EligibilityInput } from "../src/abilities-resolver/index.js";
import {
  resolveLayout,
  type TerrainTemplate as ResolverTemplate,
  type TerrainLayout as ResolverLayout,
  type ResolvedPiece,
} from "../src/terrain/resolve.js";
import {
  keystoneMeasurements,
  BOARD_INCHES,
  type KeystoneMeasurement,
} from "../src/terrain/keystones.js";

const CONFORMANCE = join(dirname(fileURLToPath(import.meta.url)), "../../conformance");
const readJson = (path: string): unknown => JSON.parse(readFileSync(path, "utf8"));
const readText = (path: string): string => readFileSync(path, "utf8");

interface InputDescriptor {
  filename: string;
  /** When `.json`, parse before importing; when `.txt`, pass the raw string. */
  parseAsJson: boolean;
}

const TEXT_EXPORTS: { format: ExportFormat; filename: string }[] = [
  { format: "newrecruit-wtc-compact", filename: "expected.newrecruit-wtc-compact.txt" },
  { format: "newrecruit-wtc-full", filename: "expected.newrecruit-wtc-full.txt" },
  { format: "newrecruit-simple", filename: "expected.newrecruit-simple.txt" },
];

const JSON_EXPORTS: { format: ExportFormat; filename: string }[] = [
  { format: "newrecruit-json", filename: "expected.newrecruit-json.json" },
  { format: "roster-json", filename: "expected.roster-json.json" },
  { format: "rosterizer", filename: "expected.rosterizer.json" },
];

function inputsFor(caseDir: string): InputDescriptor[] {
  const entries = readdirSync(caseDir);
  const inputs: InputDescriptor[] = [];
  for (const name of entries) {
    if (!name.startsWith("input.")) continue;
    inputs.push({ filename: name, parseAsJson: name.endsWith(".json") });
  }
  return inputs;
}

/**
 * Expected detected format for an `input.*` fixture, by filename convention:
 * - `input.json` is always the bare ListForge BattleScribe payload (no
 *   NewRecruit xmlns/generatedBy markers).
 * - `input.newrecruit-<sub>.<ext>` carries the format id between `input.` and
 *   the extension.
 *
 * Pins the auto-detect contract: every fixture filename is a claim about which
 * adapter must win under {@link tryImportRoster}'s greedy first-match dispatch.
 */
function expectedFormatFor(filename: string): RosterFormat {
  if (filename === "input.json") return "listforge";
  if (filename === "input.rosterizer.json") return "rosterizer";
  if (filename === "input.gw.txt") return "gw";
  if (filename === "input.listforge-text.txt") return "listforge-text";
  const match = /^input\.(newrecruit-[a-z-]+)\.[a-z]+$/.exec(filename);
  if (!match) throw new Error(`unrecognised input fixture filename: ${filename}`);
  return match[1] as RosterFormat;
}

describe("conformance corpus (ties out with the Rust crate)", () => {
  it("normalizeName matches every case in normalize.json", () => {
    const table = readJson(join(CONFORMANCE, "normalize.json")) as {
      input: string;
      expected: string;
    }[];
    expect(table.length).toBeGreaterThan(0);
    for (const { input, expected } of table) {
      expect(normalizeName(input), `normalizeName(${JSON.stringify(input)})`).toBe(expected);
    }
  });

  const ds = Dataset.embedded();
  const rosterDir = join(CONFORMANCE, "roster");
  const cases = readdirSync(rosterDir, { withFileTypes: true }).filter((e) => e.isDirectory());

  it("the roster corpus is non-empty", () => {
    expect(cases.length).toBeGreaterThan(0);
  });

  for (const entry of cases) {
    const caseDir = join(rosterDir, entry.name);
    const expected = readJson(join(caseDir, "expected.roster.json"));
    const inputs = inputsFor(caseDir);

    it(`roster/${entry.name}: tryImportRoster auto-detects the format of every input`, () => {
      expect(inputs.length).toBeGreaterThan(0);
      for (const { filename } of inputs) {
        const raw = readText(join(caseDir, filename));
        const result = tryImportRoster(raw, { dataset: ds });
        if (!result.ok) {
          throw new Error(
            `roster/${entry.name} ${filename}: expected ok, got ${result.reason}: ${result.message}`,
          );
        }
        expect(result.format, `roster/${entry.name} ${filename}`).toBe(
          expectedFormatFor(filename),
        );
      }
    });

    it(`roster/${entry.name}: every input parses to the same Roster`, () => {
      expect(inputs.length).toBeGreaterThan(0);
      for (const { filename, parseAsJson } of inputs) {
        const path = join(caseDir, filename);
        const raw = parseAsJson ? readJson(path) : readText(path);
        const actual = importRoster(raw, { dataset: ds });
        const isCanonical =
          filename === "input.json" ||
          filename === "input.newrecruit-json.json" ||
          filename === "input.gw.txt" ||
          filename === "input.listforge-text.txt";
        if (isCanonical) {
          // Canonical seed must reproduce the golden exactly.
          expect(
            JSON.parse(JSON.stringify(actual)),
            `roster/${entry.name} input ${filename}`,
          ).toEqual(expected);
        } else {
          // Derived text inputs are round-trips of the seed through an
          // exporter; format-only fields (`source.format`, `generated_by`,
          // some diagnostics) reshape, but the resolved roster shape — the
          // structural data we *can* round-trip — must still match.
          const stable = (r: unknown) => {
            const x = JSON.parse(JSON.stringify(r)) as Record<string, unknown>;
            delete x.source;
            delete x.diagnostics;
            return x;
          };
          expect(stable(actual), `roster/${entry.name} input ${filename}`).toEqual(stable(expected));
        }
      }
    });

    it(`roster/${entry.name}: canonical seed's parsed stage matches expected.parsed.json`, () => {
      // Locate the canonical seed (mirrors gen-conformance's decodeCanonicalSeed).
      const dirEntries = readdirSync(caseDir);
      let decoded: unknown;
      if (dirEntries.includes("input.json")) {
        decoded = readJson(join(caseDir, "input.json"));
      } else if (dirEntries.includes("input.newrecruit-json.json")) {
        decoded = readJson(join(caseDir, "input.newrecruit-json.json"));
      } else if (dirEntries.includes("input.gw.txt")) {
        decoded = readText(join(caseDir, "input.gw.txt"));
      } else if (dirEntries.includes("input.listforge-text.txt")) {
        decoded = readText(join(caseDir, "input.listforge-text.txt"));
      } else {
        throw new Error(`roster/${entry.name}: no canonical seed`);
      }
      const adapter = selectAdapter(decoded, [...REGISTERED_ADAPTERS]);
      const parsed = adapter.parse(decoded);
      const expectedParsed = readJson(join(caseDir, "expected.parsed.json"));
      expect(JSON.parse(JSON.stringify(parsed))).toEqual(expectedParsed);
    });

    it(`roster/${entry.name}: every export matches its golden`, () => {
      // Every fixture carries export goldens for all six formats. The
      // defensive filter below tolerates a fixture authored without one of
      // them, but in practice the present-set should always equal the full
      // export list.
      const allExports = [...TEXT_EXPORTS, ...JSON_EXPORTS];
      const dirEntries = readdirSync(caseDir);
      const present = allExports.filter((e) => dirEntries.includes(e.filename));
      if (present.length === 0) return;

      // Use the canonical seed (input.json, input.newrecruit-json.json, or the
      // text-only input.gw.txt) so the Roster we re-export is deterministic.
      const seed =
        dirEntries.find((n) => n === "input.json") ??
        dirEntries.find((n) => n === "input.newrecruit-json.json") ??
        dirEntries.find((n) => n === "input.gw.txt") ??
        dirEntries.find((n) => n === "input.listforge-text.txt");
      if (!seed) throw new Error(`no canonical input in roster/${entry.name}`);
      const seedPath = join(caseDir, seed);
      const roster = importRoster(
        seed.endsWith(".json") ? readJson(seedPath) : readText(seedPath),
        { dataset: ds },
      );

      for (const { format, filename } of present) {
        const path = join(caseDir, filename);
        const goldenText = filename.endsWith(".json")
          ? JSON.stringify(readJson(path), null, 2) + "\n"
          : readText(path);
        const actual = exportRoster(roster, format);
        expect(actual, `export ${format} for roster/${entry.name}`).toBe(goldenText);
      }
    });
  }
});

// Cruncher conformance — every case names an attacker/target by id (resolved
// against the embedded dataset), a flat `buffs` stack, an `EngineContext`,
// and an `expected.stages` map of expected-value floats. The runner asserts
// each stage matches within `5e-4` of the golden — wide enough to absorb the
// four-decimal rounding in the goldens themselves, tight enough that any
// non-trivial engine drift is caught.

const CRUNCHER_TOLERANCE = 5e-4;

interface CruncherCase {
  name: string;
  attacker: { weaponId: string; profileIndex: number };
  modelsFiring: number;
  target: { unitId: string; profileIndex: number; modelCount?: number };
  context: EngineContext;
  buffs: Buff[];
  expected: { stages: Record<Stage["name"], number> };
}

// Abilities-resolver conformance — each case names an EligibilityInput, a
// phase, and the expected ability ids grouped by source kind. Comparison is
// set-per-kind (ids are sorted before comparison), not ordered, so the
// resolver's internal iteration order is not part of the contract. See
// CONFORMANCE.md "abilities-resolver" for the rationale.

interface ResolverCase {
  name: string;
  input: EligibilityInput;
  phase: Phase;
  expected: Record<string, string[]>;
}

describe("abilities-resolver conformance corpus", () => {
  const ds = Dataset.embedded();
  const dir = join(CONFORMANCE, "abilities-resolver");
  const files = readdirSync(dir)
    .filter((n) => n.endsWith(".json") && !n.endsWith("from-dsl.json"))
    .sort();

  it("the resolver corpus is non-empty", () => {
    expect(files.length).toBeGreaterThan(0);
  });

  for (const filename of files) {
    const c = readJson(join(dir, filename)) as ResolverCase;
    it(`abilities-resolver/${filename}: ability ids per kind match the expected sets`, () => {
      const grouped: Record<string, string[]> = {};
      for (const e of ds.eligibleAbilities(c.input, c.phase)) {
        (grouped[e.source.kind] ??= []).push(e.ability.id);
      }
      for (const k of Object.keys(grouped)) grouped[k].sort();
      expect(grouped).toEqual(c.expected);
    });
  }

  type DslCase = {
    abilityId: string;
    source: { kind: "ability"; abilityId: string; abilityKind: string };
    context: EngineContext;
    perspective?: "attacker" | "target";
    expected: {
      applied: unknown[];
      unsupportedReasons: string[];
      /** Opt-in levers behind player gates, projected to id/label/group/buffs. */
      activatable?: unknown[];
    };
  };

  function runDslCorpus(filename: string): void {
    const dsl = readJson(join(dir, filename)) as { cases: DslCase[] };
    for (const c of dsl.cases) {
      const ability = ds.abilities.get(c.abilityId);
      expect(ability, `unknown ability ${c.abilityId}`).toBeDefined();
      const result = effectToBuffs(
        ability!.raw.effect,
        c.source as never,
        c.context,
        c.perspective ?? "attacker",
      );
      const appliedContribs = result.applied.map((b) => b.contribution);
      expect(
        appliedContribs,
        `applied buffs for ${c.abilityId} (${c.perspective ?? "attacker"})`,
      ).toEqual(c.expected.applied);
      const reasons = result.unsupported.map((u) => u.reason);
      expect(
        reasons,
        `unsupported reasons for ${c.abilityId} (${c.perspective ?? "attacker"})`,
      ).toEqual(c.expected.unsupportedReasons);
      if (c.expected.activatable) {
        const acts = result.activatable.map((a) => ({
          id: a.id,
          label: a.label,
          group: a.group ?? null,
          buffs: a.buffs.map((b) => b.contribution),
        }));
        expect(
          acts,
          `activatable levers for ${c.abilityId} (${c.perspective ?? "attacker"})`,
        ).toEqual(c.expected.activatable);
      }
    }
  }

  it("from-dsl.json: every case translates to the expected applied + unsupported", () => {
    runDslCorpus("from-dsl.json");
  });

  it("defensive-from-dsl.json: target-perspective translations match", () => {
    runDslCorpus("defensive-from-dsl.json");
  });
});

// Linked-API conformance — pins the cross-implementation contract for
// Dataset's read-side query methods. Each case names a query, args, and a
// comparison mode: "scalar" for id-or-null, "ordered" for data-driven array
// iteration (e.g. unit.ability_ids), "set" for queries that walk an index
// where iteration order is incidental. The corpus file is regenerated by
// `npm run gen:conformance`.
type LinkedApiComparison = "scalar" | "ordered" | "set";
interface LinkedApiCase {
  name: string;
  query: string;
  args: Record<string, string>;
  comparison: LinkedApiComparison;
  expected: string | null | string[];
}

function runLinkedApi(ds: Dataset, c: LinkedApiCase): string | null | string[] {
  switch (c.query) {
    case "find_unit":
      return ds.units.find(c.args.query)?.id ?? null;
    case "find_weapon":
      return ds.weapons.find(c.args.query)?.id ?? null;
    case "find_faction":
      return ds.factions.find(c.args.query)?.id ?? null;
    case "find_ability":
      return ds.abilities.find(c.args.query)?.id ?? null;
    case "abilities_of": {
      const u = ds.units.get(c.args.unitId);
      if (!u) throw new Error(`abilities_of: unknown unit ${c.args.unitId}`);
      return u.abilities.map((a) => a.id);
    }
    case "weapons_of": {
      const u = ds.units.get(c.args.unitId);
      if (!u) throw new Error(`weapons_of: unknown unit ${c.args.unitId}`);
      return u.weapons.map((w) => w.id);
    }
    case "wargear_options_of": {
      const u = ds.units.get(c.args.unitId);
      if (!u) throw new Error(`wargear_options_of: unknown unit ${c.args.unitId}`);
      return u.wargearOptions.map((o) => o.id);
    }
    case "maximal_loadout": {
      const u = ds.units.get(c.args.unitId);
      if (!u) throw new Error(`maximal_loadout: unknown unit ${c.args.unitId}`);
      const lo = maximalLoadout(u.raw, Number(c.args.modelCount), ds.wargearOptionsOf(u.raw));
      return [...lo.counts].map(([id, n]) => `${id}:${n}`).sort();
    }
    case "phases_of": {
      const a = ds.abilities.get(c.args.abilityId);
      if (!a) throw new Error(`phases_of: unknown ability ${c.args.abilityId}`);
      return [...a.phases];
    }
    case "faction_of": {
      const u = ds.units.get(c.args.unitId);
      if (!u) throw new Error(`faction_of: unknown unit ${c.args.unitId}`);
      return u.faction?.id ?? null;
    }
    case "abilities_of_faction":
      return ds.abilities.byFaction(c.args.factionId).map((a) => a.id);
    case "weapons_of_faction": {
      const f = ds.factions.get(c.args.factionId);
      if (!f) throw new Error(`weapons_of_faction: unknown faction ${c.args.factionId}`);
      return f.weapons.map((w) => w.id);
    }
    case "base_size_of": {
      const u = ds.units.get(c.args.unitId);
      if (!u) throw new Error(`base_size_of: unknown unit ${c.args.unitId}`);
      return encodeBase(u.raw.base_size_mm);
    }
    case "model_bases_of": {
      const u = ds.units.get(c.args.unitId);
      if (!u) throw new Error(`model_bases_of: unknown unit ${c.args.unitId}`);
      const comp = ds.unitCompositions.find((cc) => cc.unit_id === c.args.unitId);
      return (comp?.models ?? []).map((m) => `${m.name}=${encodeBase(m.base_size_mm) ?? "none"}`);
    }
    default:
      throw new Error(`unknown linked-api query: ${c.query}`);
  }
}

describe("linked-api conformance corpus", () => {
  const ds = Dataset.embedded();
  const cases = readJson(join(CONFORMANCE, "linked-api", "cases.json")) as LinkedApiCase[];

  it("the linked-api corpus is non-empty", () => {
    expect(cases.length).toBeGreaterThan(0);
  });

  for (const c of cases) {
    it(`linked-api/${c.query}: ${c.name}`, () => {
      const actual = runLinkedApi(ds, c);
      if (c.comparison === "set") {
        const sortedActual = (actual as string[]).slice().sort();
        const sortedExpected = (c.expected as string[]).slice().sort();
        expect(sortedActual).toEqual(sortedExpected);
      } else {
        expect(actual).toEqual(c.expected);
      }
    });
  }
});

// Attribution conformance — pins the per-stage leave-one-out decomposition
// from `attributeStages`. Each case references a cruncher input file (the
// same EngineInput already pinned by the cruncher corpus) and lists every
// AttributedStage's expected/baseline/residual floats, the per-group lifts
// with their sources and deltas, and the intrinsics list. Floats are
// compared with the same tolerance as the cruncher corpus.

interface AttributionCase {
  name: string;
  cruncher_case: string;
  expected: {
    name: string;
    expected: number;
    baseline: number;
    lifts: { source: unknown; delta: number }[];
    residual: number;
    intrinsics: string[];
  }[];
}

// Validator conformance — pins the closed-enum error codes the schema
// validator must emit for known invalid inputs. AJV errors are mapped to a
// small enum so the contract is language-portable; downstream validators
// (Python pydantic / jsonschema-rs, an eventual Rust validator) must reproduce
// the same codes for the same inputs. Free-form AJV messages are intentionally
// not part of the contract.
//
// The closed-enum lives in `conformance/RUNNER_PROTOCOL.md`; growing it is a
// SPEC_VERSION bump.

import { createValidator } from "../src/schema-loader.js";

interface ValidatorCase {
  name: string;
  target: string;
  input: unknown;
  expected_errors: { path: string; code: string }[];
}

const VALIDATOR_TARGET_SCHEMAS: Record<string, string> = {
  unit: "https://40kdc.dev/schemas/core/unit.schema.json",
  weapon: "https://40kdc.dev/schemas/core/weapon.schema.json",
  faction: "https://40kdc.dev/schemas/core/faction.schema.json",
  ability: "https://40kdc.dev/schemas/enrichment/ability-dsl/ability.schema.json",
  wargear: "https://40kdc.dev/schemas/core/wargear.schema.json",
  "wargear-option": "https://40kdc.dev/schemas/core/wargear-option.schema.json",
};

/** Map an AJV error to the closed-enum code defined in RUNNER_PROTOCOL.md. */
function ajvKeywordToCode(keyword: string): string {
  switch (keyword) {
    case "required":
      return "REQUIRED_MISSING";
    case "type":
      return "TYPE_MISMATCH";
    case "enum":
      return "ENUM_VIOLATION";
    case "pattern":
    case "format":
      return "PATTERN_MISMATCH";
    case "minimum":
    case "maximum":
    case "exclusiveMinimum":
    case "exclusiveMaximum":
    case "minLength":
    case "maxLength":
    case "minItems":
    case "maxItems":
      return "RANGE_VIOLATION";
    case "additionalProperties":
      return "ADDITIONAL_PROPERTY";
    case "uniqueItems":
      return "UNIQUE_VIOLATION";
    default:
      return `UNMAPPED:${keyword}`;
  }
}

/** Compute the canonical error path for a closed-enum code. */
function errorPath(err: { instancePath: string; keyword: string; params?: unknown }): string {
  if (err.keyword === "required") {
    const params = err.params as { missingProperty?: string };
    return `${err.instancePath}/${params.missingProperty ?? ""}`;
  }
  return err.instancePath;
}

describe("validator conformance corpus", () => {
  const ajv = createValidator();
  const cases = readJson(join(CONFORMANCE, "validator", "cases.json")) as ValidatorCase[];

  it("the validator corpus is non-empty", () => {
    expect(cases.length).toBeGreaterThan(0);
  });

  for (const c of cases) {
    it(`validator/${c.target}: ${c.name}`, () => {
      const schemaId = VALIDATOR_TARGET_SCHEMAS[c.target];
      if (!schemaId) throw new Error(`unknown validator target: ${c.target}`);
      const validate = ajv.getSchema(schemaId);
      if (!validate) throw new Error(`schema not loaded: ${schemaId}`);
      const ok = validate(c.input);
      const errors = (validate.errors ?? []).map((e) => ({
        path: errorPath(e),
        code: ajvKeywordToCode(e.keyword),
      }));
      // Filter: AJV emits both the specific keyword error and a containing
      // schema error in nested oneOf/anyOf cases. Keep only mapped codes and
      // dedupe by (path, code) so the closed-enum signature is what's pinned.
      const seen = new Set<string>();
      const filtered = errors
        .filter((e) => !e.code.startsWith("UNMAPPED:"))
        .filter((e) => {
          const key = `${e.path}|${e.code}`;
          if (seen.has(key)) return false;
          seen.add(key);
          return true;
        });
      if (c.expected_errors.length === 0) {
        expect(ok).toBe(true);
        expect(filtered).toEqual([]);
      } else {
        expect(ok).toBe(false);
        expect(filtered.sort((a, b) => `${a.path}|${a.code}`.localeCompare(`${b.path}|${b.code}`))).toEqual(
          c.expected_errors.slice().sort((a, b) => `${a.path}|${a.code}`.localeCompare(`${b.path}|${b.code}`)),
        );
      }
    });
  }
});

describe("attribution conformance corpus", () => {
  const ds = Dataset.embedded();
  const dir = join(CONFORMANCE, "attribution");
  const cases = readJson(join(dir, "cases.json")) as AttributionCase[];

  it("the attribution corpus is non-empty", () => {
    expect(cases.length).toBeGreaterThan(0);
  });

  for (const c of cases) {
    it(`attribution/${c.cruncher_case}: stages match within ${CRUNCHER_TOLERANCE}`, () => {
      const cruncherCasePath = join(CONFORMANCE, "cruncher", c.cruncher_case);
      const crunchInput = readJson(cruncherCasePath) as CruncherCase;
      const weapon = ds.weapons.get(crunchInput.attacker.weaponId);
      const unit = ds.units.get(crunchInput.target.unitId);
      expect(weapon).toBeDefined();
      expect(unit).toBeDefined();
      const stages = attributeStages(
        {
          attacker: { weapon: weapon!.raw, profileIndex: crunchInput.attacker.profileIndex },
          target: {
            unit: unit!.raw,
            profileIndex: crunchInput.target.profileIndex,
            ...(crunchInput.target.modelCount !== undefined
              ? { modelCount: crunchInput.target.modelCount }
              : {}),
          },
          modelsFiring: crunchInput.modelsFiring,
          buffs: crunchInput.buffs,
          context: crunchInput.context,
        },
        ds,
      );
      expect(stages.length, "stage count").toBe(c.expected.length);
      for (let i = 0; i < stages.length; i++) {
        const actual = stages[i];
        const expected = c.expected[i];
        expect(actual.name, `stage ${i} name`).toBe(expected.name);
        expect(Math.abs(actual.expected - expected.expected) < CRUNCHER_TOLERANCE).toBe(true);
        expect(Math.abs(actual.baseline - expected.baseline) < CRUNCHER_TOLERANCE).toBe(true);
        expect(Math.abs(actual.residual - expected.residual) < CRUNCHER_TOLERANCE).toBe(true);
        expect(actual.intrinsics, `stage ${expected.name} intrinsics`).toEqual(expected.intrinsics);
        expect(actual.lifts.length, `stage ${expected.name} lift count`).toBe(expected.lifts.length);
        for (let j = 0; j < actual.lifts.length; j++) {
          expect(actual.lifts[j].source).toEqual(expected.lifts[j].source);
          expect(
            Math.abs(actual.lifts[j].delta - expected.lifts[j].delta) < CRUNCHER_TOLERANCE,
          ).toBe(true);
        }
      }
    });
  }
});

// Terrain-resolver conformance — pins the template-anchored layout → board
// vertex geometry. Each case carries its own templates + layout and the
// expected resolved pieces. Vertices compared within 5e-4 (the corpus float
// tolerance); piece id/name/type/floor compared exactly. The Rust port asserts
// against the same corpus (crates/wh40kdc/tests/terrain_resolver_conformance.rs).
const TERRAIN_TOLERANCE = 5e-4;

interface TerrainCase {
  name: string;
  templates: ResolverTemplate[];
  layout: ResolverLayout;
  expected: { pieces: ResolvedPiece[] };
}

describe("terrain-resolver conformance corpus", () => {
  const cases = readJson(join(CONFORMANCE, "terrain-resolver", "cases.json")) as TerrainCase[];

  it("the terrain-resolver corpus is non-empty", () => {
    expect(cases.length).toBeGreaterThan(0);
  });

  for (const c of cases) {
    it(`terrain-resolver/${c.name}: resolved vertices match within ${TERRAIN_TOLERANCE}`, () => {
      const actual = resolveLayout(c.layout, c.templates);
      expect(actual.length, "piece count").toBe(c.expected.pieces.length);
      for (let i = 0; i < actual.length; i++) {
        const a = actual[i];
        const e = c.expected.pieces[i];
        expect(a.id, `piece ${i} id`).toBe(e.id);
        expect(a.name, `piece ${i} name`).toBe(e.name);
        expect(a.piece_type, `piece ${i} type`).toBe(e.piece_type);
        expect(a.floor, `piece ${i} floor`).toBe(e.floor);
        expect(a.vertices.length, `piece ${i} vertex count`).toBe(e.vertices.length);
        for (let j = 0; j < a.vertices.length; j++) {
          expect(Math.abs(a.vertices[j].x - e.vertices[j].x), `piece ${i} vert ${j} x`).toBeLessThanOrEqual(TERRAIN_TOLERANCE);
          expect(Math.abs(a.vertices[j].y - e.vertices[j].y), `piece ${i} vert ${j} y`).toBeLessThanOrEqual(TERRAIN_TOLERANCE);
        }
      }
    });
  }
});

// Terrain-keystones conformance — pins the derivation of authored keystone
// distances (board edge → piece feature) from resolved geometry. The Rust
// port asserts against the same corpus
// (crates/wh40kdc/tests/terrain_keystones_conformance.rs).

interface KeystoneCase {
  name: string;
  templates: ResolverTemplate[];
  layout: ResolverLayout;
  board?: { width: number; height: number };
  expected: { measurements: KeystoneMeasurement[] };
}

describe("terrain-keystones conformance corpus", () => {
  const cases = readJson(join(CONFORMANCE, "terrain-keystones", "cases.json")) as KeystoneCase[];

  it("the terrain-keystones corpus is non-empty", () => {
    expect(cases.length).toBeGreaterThan(0);
  });

  for (const c of cases) {
    it(`terrain-keystones/${c.name}: distances match within ${TERRAIN_TOLERANCE}`, () => {
      const actual = keystoneMeasurements(c.layout, c.templates, c.board ?? BOARD_INCHES);
      expect(actual.length, "measurement count").toBe(c.expected.measurements.length);
      for (let i = 0; i < actual.length; i++) {
        const a = actual[i];
        const e = c.expected.measurements[i];
        expect(a.piece_index, `measurement ${i} piece_index`).toBe(e.piece_index);
        expect(a.piece_id, `measurement ${i} piece_id`).toBe(e.piece_id);
        expect(a.edge, `measurement ${i} edge`).toBe(e.edge);
        expect(a.ref, `measurement ${i} ref`).toEqual(e.ref);
        expect(Math.abs(a.distance - e.distance), `measurement ${i} distance`).toBeLessThanOrEqual(TERRAIN_TOLERANCE);
      }
    });
  }
});

// Scoring conformance — pins the pure VP arithmetic of the scoring engine
// (`score_event`, `score_state`, `wtc_result`). Each case is dispatched through
// the runner — the same path the cross-impl differ drives — and the value is
// compared exactly (integers, no tolerance). The Rust port asserts against the
// same corpus (crates/wh40kdc/tests/scoring_conformance.rs).

import { createRunnerState, dispatch } from "../src/runner.js";

interface ScoringCase {
  name: string;
  op: string;
  args: unknown;
  expected: unknown;
}

describe("scoring conformance corpus", () => {
  const cases = readJson(join(CONFORMANCE, "scoring", "cases.json")) as ScoringCase[];
  const specVersion = Number.parseInt(
    readFileSync(join(CONFORMANCE, "SPEC_VERSION"), "utf8").trim(),
    10,
  );
  const state = createRunnerState();
  const init = dispatch(state, {
    op: "init",
    args: { spec_version: specVersion, locale: "C", tz: "UTC", seed: 0 },
  });

  it("the runner initializes at the corpus spec version", () => {
    expect(init.ok, JSON.stringify(init)).toBe(true);
  });

  it("the scoring corpus is non-empty", () => {
    expect(cases.length).toBeGreaterThan(0);
  });

  for (const c of cases) {
    it(`scoring/${c.name}`, () => {
      const res = dispatch(state, { op: c.op, args: c.args });
      expect(res.ok, `op ${c.op} errored: ${JSON.stringify(res)}`).toBe(true);
      if (res.ok) expect(res.value).toEqual(c.expected);
    });
  }
});

describe("cruncher conformance corpus", () => {
  const ds = Dataset.embedded();
  const cruncherDir = join(CONFORMANCE, "cruncher");
  const files = readdirSync(cruncherDir).filter((n) => n.endsWith(".json")).sort();

  it("the cruncher corpus is non-empty", () => {
    expect(files.length).toBeGreaterThan(0);
  });

  for (const filename of files) {
    const path = join(cruncherDir, filename);
    const c = readJson(path) as CruncherCase;
    it(`cruncher/${filename}: stages match the golden within ${CRUNCHER_TOLERANCE}`, () => {
      const weapon = ds.weapons.get(c.attacker.weaponId);
      const unit = ds.units.get(c.target.unitId);
      expect(weapon, `unknown weapon ${c.attacker.weaponId} in ${filename}`).toBeDefined();
      expect(unit, `unknown unit ${c.target.unitId} in ${filename}`).toBeDefined();
      const out = crunch(
        {
          attacker: { weapon: weapon!.raw, profileIndex: c.attacker.profileIndex },
          target: {
            unit: unit!.raw,
            profileIndex: c.target.profileIndex,
            ...(c.target.modelCount !== undefined ? { modelCount: c.target.modelCount } : {}),
          },
          modelsFiring: c.modelsFiring,
          buffs: c.buffs,
          context: c.context,
        },
        ds,
      );
      const actualByName = Object.fromEntries(out.stages.map((s) => [s.name, s.expected])) as Record<
        Stage["name"],
        number
      >;
      for (const [name, expected] of Object.entries(c.expected.stages) as [Stage["name"], number][]) {
        const actual = actualByName[name];
        expect(actual, `stage ${name} missing in ${filename}`).toBeDefined();
        const delta = Math.abs(actual - expected);
        expect(
          delta < CRUNCHER_TOLERANCE,
          `cruncher/${filename} stage ${name}: expected ${expected.toFixed(6)}, got ${actual.toFixed(6)} (Δ ${delta.toFixed(6)})`,
        ).toBe(true);
      }
    });
  }
});
